# break fires → else skipped
while a < 3:
    ...
    break
else:
    print('no errors!')   # NOT printed

# loop exhausted → else runs
while a < 3:
    a += 1
else:
    print('no errors!')   # printed

def risky():
    try:
        raise ValueError('oops')
    finally:
        return 42   # exception swallowed! returns 42 silently

risky()  # returns 42, ValueError is gone
